257	func resolveStrongSplitterMinPower(ctx context.Context, projectRoot string, svc agentlib.FizeauService) int {
258		if svc == nil {
259			return 0
260		}
261	
262		models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
263		if err != nil {
264			return 0
265		}
266		maxPower := 0
267		for _, m := range models {
268			if m.Power > maxPower {
269				maxPower = m.Power
270			}
271		}
272		return maxPower
273	}
274	
275	func isStrongPowerUnsatisfiedError(err error) bool {
276		if err == nil {
277			return false
278		}
279		switch ClassifyFailureMode("task_failed", 1, err.Error()) {
280		case FailureModeAgentPowerUnsatisfied, FailureModeBlockedByPassthroughConstraint:
281			return true
282		default:
283			return false
284		}
285	}
286	
287	func isSmartProfileUnavailableError(err error) bool {
288		if err == nil {
289			return false
290		}
291		msg := strings.ToLower(err.Error())
292		return strings.Contains(msg, "tier ≥ smart") ||
293			strings.Contains(msg, "tier >= smart") ||
294			strings.Contains(msg, "profile=smart") ||
295			strings.Contains(msg, "profile smart")
296	}
